#include<bits/stdc++.h>
using namespace std;
int dp[1001][1001],a[1001],s[1001],x[1001][1001],y[1001][1001];
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        memset(dp,0,sizeof(dp));
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
            s[i]=s[i-1]+a[i];
            dp[i][i]=x[i][i]=y[i][i]=a[i];
        }
        for(int len=2;len<=n;len++)
        {
            for(int l=1;l+len-1<=n;l++)
            {
                int r=l+len-1;
                int sum=s[r]-s[l-1];
                dp[l][r]=max({sum,sum-x[l+1][r],sum-y[l][r-1]});
                x[l][r]=min(x[l+1][r],dp[l][r]);
                y[l][r]=min(y[l][r-1],dp[l][r]);
            }
        }
        printf("%d\n",dp[1][n]);
    }
    return 0;
}
